import { createContext } from "react";
export const defaultToLocalDateTime = d => (typeof d === "string" ? new Date(d) : d);
export const userFormatContext = createContext({
    dateFormat: "yyyy-MM-dd",
    timeFormat: "HH:mm",
    weekStartsOnSunday: false,
    toLocalDateTime: defaultToLocalDateTime,
    toReverseOffsetDateTime: defaultToLocalDateTime
});
