/**
 * Converts a string to kebab-case for use in analytics IDs.
 * Handles camelCase, parentheses, and spaces.
 *
 * Inspired by `toKebabCase` in `apps/MyGeotab/src/shared/utils/analyticsUtils.ts`
 * to ensure consistent analytics ID formatting across Zenith and MyGeotab.
 *
 * @param str - The string to convert.
 * @returns The kebab-case string.
 *
 * @example
 * toKebabCase("breakdownRate") // "breakdown-rate"
 * toKebabCase("Fuel Level (EV)") // "fuel-level-ev"
 * toKebabCase("State of Charge") // "state-of-charge"
 */
export const toKebabCase = (str) => str
    .replace(/([a-z])([A-Z])/g, "$1-$2")
    .replace(/[()]/g, "")
    .trim()
    .replace(/\s+/g, "-")
    .toLowerCase();
