export const getMaxNumberOfActions = (size) => {
    switch (size) {
        case "XXL":
        case "XL": {
            return 4;
        }
        case "L": {
            return 3;
        }
        case "M": {
            return 2;
        }
        case "S": {
            return 1;
        }
        case "XS":
        case "XXS":
        default: {
            return 1;
        }
    }
};
