export const getContainerSize = (width) => {
    if (!width) {
        return "M";
    }
    if (width >= 753) {
        return "XL";
    }
    if (width >= 561) {
        return "L";
    }
    if (width >= 369) {
        return "M";
    }
    if (width >= 273) {
        return "S";
    }
    return "XXS";
};
