export const getParentWindow = win => {
    if (win.parent) {
        if (win.parent === win) {
            return win;
        }
        try {
            // iframe may not have access to the parent window, need to check it
            if (win.parent.innerWidth) {
                return getParentWindow(win.parent);
            }
        }
        catch (e) { }
        return win;
    }
    return win;
};
