import { useMemo } from "react";
import { ActionsColumn } from "../../dataGrid/columns/actionsColumn/actionsColumn";
export const useActions = (columns, isFeed) => {
    const result = useMemo(() => {
        if (!isFeed) {
            return { columnsWithActions: [...columns], actions: undefined, actionsAsync: undefined };
        }
        const columnsWithActions = columns.find(el => el.columnComponent instanceof ActionsColumn);
        let actions = undefined;
        let actionsAsync = undefined;
        let primaryActions = undefined;
        if (columnsWithActions && columnsWithActions.columnComponent) {
            const colComponent = columnsWithActions.columnComponent;
            actions = colComponent.columnActions;
            actionsAsync = colComponent.columnActionsAsync;
            primaryActions = colComponent.columnPrimaryActions;
        }
        const columnsWithoutActions = columns.filter(el => !(el.columnComponent instanceof ActionsColumn));
        return { columnsWithActions: columnsWithoutActions, actions, actionsAsync, primaryActions };
    }, [columns, isFeed]);
    return result;
};
