import { useMobile } from "../../commonHelpers/hooks/useMobile";
import { useDrive } from "./useDrive";
export const useDriveClassName = (className) => {
    const isDrive = useDrive();
    const isMobile = useMobile();
    if (!isDrive) {
        return undefined;
    }
    if (isMobile) {
        return `${className}--drive`;
    }
    return `${className}--drive-tablet`;
};
